#!/bin/bash
cd ~/dumpsite-io
node -e "const {createClient}=require('@supabase/supabase-js');require('dotenv').config({path:'.env.local'});const s=createClient(process.env.NEXT_PUBLIC_SUPABASE_URL,process.env.SUPABASE_SERVICE_ROLE_KEY);const fs=require('fs');const {execSync}=require('child_process');async function b(){const o=await s.from('dispatch_orders').select('id',{count:'exact'}).in('status',['dispatching','active','pending']);const d=await s.from('driver_profiles').select('id',{count:'exact'}).eq('status','active');const c=execSync('git log --oneline -1').toString().trim();let md=fs.readFileSync('SESSION.md','utf8');md=md.replace(/Open orders: \d+/,'Open orders: '+(o.count||0));md=md.replace(/Active drivers: \d+/,'Active drivers: '+(d.count||0));md=md.replace(/>.*Auto-generated.*/,'> Auto-generated '+new Date().toISOString());md=md.replace(/> Commit:.*/,'> Commit: '+c);fs.writeFileSync('SESSION.md',md);console.log('✓ SESSION.md refreshed with live stats')}b().catch(console.error)"
